import {
  Camera,
  CameraResultType,
  CameraSource,
  ImageOptions,
} from "@capacitor/camera";
import { Geolocation } from "@capacitor/geolocation";
import { Capacitor } from "@capacitor/core";
import { LoanUsage } from "../../../Models/Loan/LoanUsage";
import { forkJoin, Observable, Subscription } from "rxjs";
