import { AlertService } from "src/app/core/services/alert.service";
import { pagingService } from "src/app/core/services/paging.service";
import { sortingService } from "src/app/core/services/sorting.service";
import { IDocActions } from "src/app/views/Models/References/DocActions";
import { LoanRejection } from "src/app/views/Models/Loan/LoanRejection";
import { LoanRejectionParent } from "src/app/views/Models/Loan/Rejection";
import { OfficersVisitsWorkFlow } from "src/app/views/Models/Officer/OfficerVisitsWorkFlow";
import { StaticRef } from "src/app/views/Models/References/StaticRef";
import { CameraService } from "src/app/core/services/camera.service";
import {
  DocumentsInformation,
  GetDocumentsByApplicationKey,
} from "src/app/views/Models/Documents/GetDocumentByApplicationKey";
import { DocumentService } from "src/app/core/services/document.service";
import { ExportingService } from "src/app/core/services/exporting.service";
import { PostDocumentByApplicationKeyHierarchy } from "src/app/views/Models/Documents/PostDocumentByApplicationKeyHierarchy";

enum FieldReviewPageMode {
  Search,
  Review,
}
interface ExtendedDocumentsByApplicationKey
  extends GetDocumentsByApplicationKey {
  numberOfImagesExist: number;
}
interface ExtendedDocumentModalObject extends DocumentsInformation {
  documentTypeDescription: string;
  documentTypeCode: number;
}

interface ClientDocuments {
  allDocumentsFromDb: ExtendedDocumentsByApplicationKey[];
}
interface DocumentModalObject {
  visible: boolean;
  selectedDocument: ExtendedDocumentModalObject;
  platform: string;
}

@Component({
  selector: "app-field-review-workflow",
  templateUrl: "./field-review-workflow.page.html",
  styleUrls: ["./field-review-workflow.page.scss"],
})
export class FieldReviewWorkflowPage implements OnInit {
  backButtonListener: Subscription;
  FieldReviewPageMode: typeof FieldReviewPageMode = FieldReviewPageMode;
  pageMode: FieldReviewPageMode;

  @ViewChild("imageModal") imageModal: IonModal;

  displayDocuments: boolean = false;
  showLoader: boolean = false;
  isSubmitted: boolean = false;
  RandomSelection: number = 0;

  constructor(
    private env: EnvService,
    private http: HttpClient,
    private formBuilder: FormBuilder,
    private alertController: AlertController,
    private activatedRoute: ActivatedRoute,
    private toastController: ToastController,
    private datePipe: DatePipe,
    private webIntent: WebIntent,
    private router: Router,
    private stateService: StateService,
    private locationService: LocationService,
    private authService: MohassilAuthService,
    private sortingService: sortingService,
    public pagingService: pagingService,
    private datepipe: DatePipe,
    private alertService: AlertService,
    private platform: Platform,
    private cameraService: CameraService,
    private documentService: DocumentService,
    private exportingService: ExportingService
  ) {}
  //#region Variable
  sortingIconClass: string;
  sortingIconParam: string;

  loan_int_type: StaticRef[];
  allDocs: any[];
  ClientDocuments: any;
  docActions: IDocActions[];
  clientTypes: IClientType[];
  officers: IOfficer[];
  loanUsages: LoanUsage[];
  LoanTypes: LoanTypeRef[];
  LoanRej: LoanRejection[];
  RejectionParent: LoanRejectionParent[];
  iscore_external_funding: string;
  isIscore_external_funding: boolean = false;
  loanTypeInfo;
  isvalids: boolean = false;
  isDateAssignedRequired: boolean = false;
  isRejected: boolean = false;
  canEdit: boolean = false;
  canEditLoanIntRT: boolean = false;
  officer_key: string;
  client_type_code: string;
  job_id;
  org_code: string;

  loanApplications: ApplicationClient[];
  selectedLoanApplication: ApplicationClient;
  validationErrors: string = "";

  lastVisits: OfficersVisitsWorkFlow[];
  isLastVisits: boolean = false;
  hasDocs: boolean = false;

  page: number = 1; // the page we are viewing
  count: number = 1;

  OfficerLong;
  OfficerLat;
  OfficerZoom;

  clientDocuments: ClientDocuments = { allDocumentsFromDb: [] };
  documentModalObject: DocumentModalObject = {
    visible: false,
    selectedDocument: {
      imageDate: null,
      pageNumber: null,
      documentTypeDescription: null,
      documentTypeCode: null,
      imageExist:false
    },
    platform: null,
  };
  //#endregion
  async ngOnInit(): Promise<void> {
    let params = this.activatedRoute.snapshot.queryParams;
    await this.authService.getUserInfo().then((userInfo) => {
      this.job_id = userInfo.workflow_job_id;
      this.org_code = userInfo.org_code;
    });
    await this.getOfficerLocation();
    await this.searchLoanApplications();
    this.pageMode = FieldReviewPageMode.Search;

    if (params["applicationKey"] && params["clientTypeCode"]) {
      await this.reviewInitiatedFromNotifications(
        params["applicationKey"],
        params["clientTypeCode"]
      );
    }

    this.documentModalObject.platform = Capacitor.getPlatform();
  }

  removeURLParams(): void {
    // Get the current URL without parameters
    const baseUrl: string = window.location.href.split("?")[0];
    window.history.replaceState({}, document.title, baseUrl);
  }
  backButton(): void {
    if (this.pageMode != FieldReviewPageMode.Search) {
      // Loan application selected
      if (this.pageMode == FieldReviewPageMode.Review) {
        this.cancel();
      }
    } else {
      this.router.navigate(["/"]);
    }
  }

  async searchLoanApplications() {
    try {
      this.showLoader = true;
      let data = await this.http
        .post<ApplicationClient[]>(
          this.env.API_URL +
            `api/LoanApplications/GetApplicationsToReviseWorkflow`,
          {
            officer_key: null,
            client_type_code: "0",
            all_officers: "1",
            job_id: this.job_id,
            officerLat: this.OfficerLat,
            officerLong: this.OfficerLong,
            randomSelection: this.RandomSelection,
          }
        )
        .toPromise();
      this.loanApplications = data;
      this.showLoader = false;
    } catch (err) {
      this.alertService.showAlertError("خطأ في الاتصال بالخادم", false);
      this.showLoader = false;
    }
  }

  changePage(newPage: number): void {
    this.page = newPage;
  }

  async review(loanApplication: ApplicationClient) {
    this.selectedLoanApplication = loanApplication;
    this.pageMode = FieldReviewPageMode.Review;
  }

  async reviewInitiatedFromNotifications(
    applicationKey: string,
    clientTypeCode: string
  ) {
    let data = await this.http
      .post<ApplicationClient[]>(
        this.env.API_URL +
          `api/LoanApplications/GetApplicationsToReviseWorkflow`,
        {
          officer_key: "0",
          client_type_code: clientTypeCode,
          all_officers: "1",
          job_id: this.job_id,
          officerLat: this.OfficerLat,
          officerLong: this.OfficerLong,
          randomSelection: 0,
        }
      )
      .toPromise();
    this.loanApplications = data;
    var loanApplication = this.loanApplications.filter(
      (x) => x.applicationKey == applicationKey
    )[0];
    this.selectedLoanApplication = loanApplication;

    this.pageMode = FieldReviewPageMode.Review;
  }

  cancel(): void {
    if (this.RandomSelection == 1) {
      this.loanApplications = null;
    }
    this.pageMode = FieldReviewPageMode.Search;
    this.selectedLoanApplication = null;
    this.lastVisits = [];
    this.isSubmitted = false;
  }

  NumberFormatStyle(number) {
    let result = formatNumber(Number(number), "en-US", "1.0");
    return result;
  }

  DateFormatStyle(input: string) {
    return this.datePipe.transform(input, "yyyy-MM-dd");
  }

  paging() {
    this.count = this.pagingService.totalCount;
    return this.pagingService.Paging(this.loanApplications, this.page);
  }

  sortingTable(data: any, param: string) {
    this.sortingService.sortByParameter(data, param);
    this.sortingIconClass =
      this.sortingService.sortOrder === "asc"
        ? "arrow-down-outline"
        : "arrow-up-outline";
    this.sortingIconParam = param;
  }
  async getOfficerLocation(): Promise<void> {
    if (Capacitor.getPlatform() != "web") {
      this.showLoader = true;
      try {
        let locationResult: GeolocationResult =
          await this.locationService.getLocation();
        if (!locationResult.success) {
          this.alertService.showAlertError(locationResult.message, false);
          this.showLoader = false;
          return;
        }

        this.OfficerLat = locationResult.position?.coords.latitude.toString();
        this.OfficerLong = locationResult.position?.coords.longitude.toString();
        this.OfficerZoom = "0";
        this.showLoader = false;
      } catch (error) {
        this.showLoader = false;
      }
    }
  }
}
